# lib/admin_dashboard/result_parser.ex
defmodule AdminDashboard.ResultParser do
  @moduledoc """
  Converts raw `Postgrex.Result` structs into maps for easy consumption.
  """

  def to_maps(%Postgrex.Result{columns: columns, rows: rows}) when is_list(columns) do
    Enum.map(rows, fn row ->
      columns
      |> Enum.zip(row)
      |> Map.new()
    end)
  end

  def to_maps(_), do: []

  def to_single_value(%Postgrex.Result{rows: [[value | _] | _]}), do: value
  def to_single_value(_), do: nil
end

# lib/admin_dashboard_web/controllers/admin_user_controller.ex
defmodule AdminDashboardWeb.AdminUserController do
  use AdminDashboardWeb, :controller

  alias AdminDashboard.QueryBuilder
  alias AdminDashboard.ResultParser

  def index(conn, params) do
    role = Map.get(params, "role")
    search = Map.get(params, "search")
    sort_by = Map.get(params, "sort_by", "created_at")
    sort_dir = Map.get(params, "sort_dir", "desc")
    page = params |> Map.get("page", "1") |> String.to_integer() |> max(1)
    per_page = params |> Map.get("per_page", "25") |> String.to_integer() |> min(100)
    offset = (page - 1) * per_page

    filters = build_filters_from_params(params)

    case QueryBuilder.get_users_filtered(
           filters: filters,
           sort_by: sort_by,
           sort_dir: sort_dir,
           limit: per_page,
           offset: offset
         ) do
      {:ok, result} ->
        users = ResultParser.to_maps(result)

        total_count =
          case QueryBuilder.count_users_filtered(filters) do
            {:ok, count_result} -> ResultParser.to_single_value(count_result) || 0
            _ -> 0
          end

        conn
        |> put_status(:ok)
        |> json(%{
          users: users,
          pagination: %{
            page: page,
            per_page: per_page,
            total: total_count,
            total_pages: ceil(total_count / per_page)
          }
        })

      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: reason})
    end
  end

  def show(conn, %{"id" => id}) do
    user_id = String.to_integer(id)

    case QueryBuilder.get_user_by_id(user_id) do
      {:ok, result} ->
        case ResultParser.to_maps(result) do
          [user | _] -> json(conn, %{user: user})
          [] -> conn |> put_status(:not_found) |> json(%{error: "User not found"})
        end

      {:error, reason} ->
        conn |> put_status(:bad_request) |> json(%{error: reason})
    end
  end

  def search(conn, %{"q" => query_term}) do
    case QueryBuilder.search_users(query_term) do
      {:ok, result} ->
        json(conn, %{users: ResultParser.to_maps(result)})

      {:error, reason} ->
        conn |> put_status(:bad_request) |> json(%{error: reason})
    end
  end

  def update_status(conn, %{"id" => id, "status" => status}) do
    user_id = String.to_integer(id)

    case QueryBuilder.update_user_status(user_id, status) do
      {:ok, _result} ->
        json(conn, %{message: "User status updated successfully"})

      {:error, reason} ->
        conn |> put_status(:bad_request) |> json(%{error: reason})
    end
  end

  # Build filter tuples from query params, ignoring unknown keys
  defp build_filters_from_params(params) do
    []
    |> maybe_add_filter(params, "role", "=")
    |> maybe_add_filter(params, "status", "=")
  end

  defp maybe_add_filter(filters, params, key, operator) do
    case Map.get(params, key) do
      nil -> filters
      "" -> filters
      value -> [{"#{key}", operator, value} | filters]
    end
  end
end

# test/admin_dashboard/query_builder_test.exs
defmodule AdminDashboard.QueryBuilderTest do
  use ExUnit.Case, async: true

  alias AdminDashboard.QueryBuilder

  describe "validation prevents SQL injection" do
    test "rejects invalid role" do
      assert {:error, _} = QueryBuilder.get_users_by_role("admin'; DROP TABLE users; --")
    end

    test "accepts valid role" do
      # This would succeed if the Repo were available
      assert {:error, _} = QueryBuilder.get_users_by_role("admin'; DROP TABLE users;--")
    end

    test "rejects invalid sort column" do
      assert {:error, _} =
               QueryBuilder.get_users_filtered(
                 sort_by: "1; DROP TABLE users;--",
                 sort_dir: "asc"
               )
    end

    test "rejects invalid sort direction" do
      assert {:error, _} =
               QueryBuilder.get_users_filtered(
                 sort_by: "created_at",
                 sort_dir: "asc; DROP TABLE users;--"
               )
    end

    test "rejects invalid comparison operator in filters" do
      assert {:error, _} =
               QueryBuilder.get_users_filtered(
                 filters: [{"role", "= ''; DROP TABLE users;--", "admin"}]
               )
    end

    test "rejects invalid filter column" do
      assert {:error, _} =
               QueryBuilder.get_users_filtered(
                 filters: [{"nonexistent_column", "=", "value"}]
               )
    end

    test "rejects invalid table name" do
      assert {:error, _} = QueryBuilder.get_records_from_table("users; DROP TABLE users;--")
    end

    test "rejects invalid status" do
      assert {:error, _} = QueryBuilder.update_user_status(1, "active'; DROP TABLE users;--")
    end
  end

  describe "LIKE pattern escaping" do
    test "search_users_by_username escapes special LIKE characters" do
      # The function should not crash and should escape %, _, and \
      # In a real test with a database, we'd verify the escaped pattern
      # Here we just verify the function head matches
      assert is_function(&QueryBuilder.search_users_by_username/1)
    end
  end
end